use crate::types::{DecideInput, DecideOutput};
use std::f64::consts::PI;

/// Compares two real numbers with six-significant-digit precision
fn realcompare(a: f64, b: f64) -> &'static str {
    const EPSILON: f64 = 1e-6;
    let diff = (a - b).abs();
    let max_val = a.abs().max(b.abs());

    // If both values are very close to zero
    if max_val < EPSILON {
        return "EQ";
    }

    // Relative comparison for six significant digits
    let relative_epsilon = max_val * EPSILON;

    if diff < relative_epsilon {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

/// Calculate distance between two points
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

/// Calculate angle at vertex point (x2, y2) formed by rays to (x1, y1) and (x3, y3)
fn angle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    // Check if vertex coincides with either other point
    if (realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ") ||
       (realcompare(x3, x2) == "EQ" && realcompare(y3, y2) == "EQ") {
        return None; // Angle is undefined
    }

    let v1x = x1 - x2;
    let v1y = y1 - y2;
    let v2x = x3 - x2;
    let v2y = y3 - y2;

    let dot_product = v1x * v2x + v1y * v2y;
    let mag1 = (v1x * v1x + v1y * v1y).sqrt();
    let mag2 = (v2x * v2x + v2y * v2y).sqrt();

    if realcompare(mag1, 0.0) == "EQ" || realcompare(mag2, 0.0) == "EQ" {
        return None; // Angle is undefined
    }

    let cos_angle = dot_product / (mag1 * mag2);
    // Clamp to [-1, 1] to handle numerical errors
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    Some(cos_angle.acos())
}

/// Calculate area of triangle formed by three points
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs())
}

/// Check if three points can be contained within or on a circle of given radius
fn points_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // Check if any two points are more than 2*radius apart
    if realcompare(distance(x1, y1, x2, y2), 2.0 * radius) == "GT" ||
       realcompare(distance(x2, y2, x3, y3), 2.0 * radius) == "GT" ||
       realcompare(distance(x1, y1, x3, y3), 2.0 * radius) == "GT" {
        return false;
    }

    // Calculate circumradius of triangle
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    let a = distance(x2, y2, x3, y3);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x1, y1, x2, y2);

    // If area is zero, points are collinear
    if realcompare(area, 0.0) == "EQ" {
        let max_dist = a.max(b).max(c);
        return realcompare(max_dist / 2.0, radius) != "GT";
    }

    let circumradius = (a * b * c) / (4.0 * area);
    realcompare(circumradius, radius) != "GT"
}

/// Determine which quadrant a point is in
fn quadrant(x: f64, y: f64) -> usize {
    match (realcompare(x, 0.0), realcompare(y, 0.0)) {
        ("GT", _) | ("EQ", "GT") | ("EQ", "EQ") => 1, // I: x >= 0, y >= 0 (priority to I)
        ("LT", "GT") | ("LT", "EQ") => 2,              // II: x < 0, y >= 0
        ("LT", "LT") => 3,                             // III: x < 0, y < 0
        (_, "LT") => 4,                                // IV: x >= 0, y < 0
    }
}

/// Calculate distance from a point to a line defined by two other points
fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    // If line endpoints are the same, return distance to that point
    if realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ" {
        return distance(px, py, x1, y1);
    }

    let a = y2 - y1;
    let b = x1 - x2;
    let c = x2 * y1 - x1 * y2;

    let numerator = (a * px + b * py + c).abs();
    let denominator = (a * a + b * b).sqrt();

    numerator / denominator
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let numpoints = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let params = &input.parameters;

    // Initialize CMV (Conditions Met Vector)
    let mut cmv = vec![false; 15];

    // LIC 1: Two consecutive points distance > LENGTH1
    if numpoints >= 2 {
        for i in 0..(numpoints - 1) {
            let dist = distance(x[i], y[i], x[i + 1], y[i + 1]);
            if realcompare(dist, params.length1) == "GT" {
                cmv[0] = true;
                break;
            }
        }
    }

    // LIC 2: Three consecutive points cannot be contained in circle of radius RADIUS1
    if numpoints >= 3 {
        for i in 0..(numpoints - 2) {
            if !points_in_circle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], params.radius1) {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 3: Three consecutive points form angle < (PI - EPSILON) or > (PI + EPSILON)
    if numpoints >= 3 {
        for i in 0..(numpoints - 2) {
            if let Some(ang) = angle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
                if realcompare(ang, PI - params.epsilon) == "LT" ||
                   realcompare(ang, PI + params.epsilon) == "GT" {
                    cmv[2] = true;
                    break;
                }
            }
        }
    }

    // LIC 4: Three consecutive points form triangle with area > AREA1
    if numpoints >= 3 {
        for i in 0..(numpoints - 2) {
            let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
            if realcompare(area, params.area1) == "GT" {
                cmv[3] = true;
                break;
            }
        }
    }

    // LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants
    if numpoints >= params.q_pts && params.q_pts >= 2 {
        for i in 0..(numpoints - params.q_pts + 1) {
            let mut quadrants = vec![false; 4];
            for j in i..(i + params.q_pts) {
                quadrants[quadrant(x[j], y[j]) - 1] = true;
            }
            let quad_count = quadrants.iter().filter(|&&q| q).count();
            if quad_count > params.quads {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6: Two consecutive points with X[j] - X[i] < 0
    if numpoints >= 2 {
        for i in 0..(numpoints - 1) {
            if realcompare(x[i + 1], x[i]) == "LT" {
                cmv[5] = true;
                break;
            }
        }
    }

    // LIC 7: N_PTS consecutive points with at least one point distance > DIST from line
    if numpoints >= 3 && numpoints >= params.n_pts && params.n_pts >= 3 {
        for i in 0..(numpoints - params.n_pts + 1) {
            let first_idx = i;
            let last_idx = i + params.n_pts - 1;
            let mut found = false;

            for j in (i + 1)..last_idx {
                let dist = point_to_line_distance(x[j], y[j], x[first_idx], y[first_idx], x[last_idx], y[last_idx]);
                if realcompare(dist, params.dist) == "GT" {
                    found = true;
                    break;
                }
            }

            if found {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8: Two points separated by K_PTS consecutive intervening points, distance > LENGTH1
    if numpoints >= 3 {
        for i in 0..(numpoints - params.k_pts - 1) {
            let j = i + params.k_pts + 1;
            let dist = distance(x[i], y[i], x[j], y[j]);
            if realcompare(dist, params.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS, cannot be contained in circle of radius RADIUS1
    if numpoints >= 5 {
        for i in 0..(numpoints - params.a_pts - params.b_pts - 2) {
            let j = i + params.a_pts + 1;
            let k = j + params.b_pts + 1;
            if !points_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius1) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS form angle < (PI - EPSILON) or > (PI + EPSILON)
    if numpoints >= 5 {
        for i in 0..(numpoints - params.c_pts - params.d_pts - 2) {
            let j = i + params.c_pts + 1;
            let k = j + params.d_pts + 1;
            if let Some(ang) = angle(x[i], y[i], x[j], y[j], x[k], y[k]) {
                if realcompare(ang, PI - params.epsilon) == "LT" ||
                   realcompare(ang, PI + params.epsilon) == "GT" {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS form triangle with area > AREA1
    if numpoints >= 5 {
        for i in 0..(numpoints - params.e_pts - params.f_pts - 2) {
            let j = i + params.e_pts + 1;
            let k = j + params.f_pts + 1;
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, params.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12: Two points separated by G_PTS with X[j] - X[i] < 0
    if numpoints >= 3 {
        for i in 0..(numpoints - params.g_pts - 1) {
            let j = i + params.g_pts + 1;
            if realcompare(x[j], x[i]) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13: Two conditions both must be true
    if numpoints >= 3 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..(numpoints - params.k_pts - 1) {
            let j = i + params.k_pts + 1;
            let dist = distance(x[i], y[i], x[j], y[j]);
            if realcompare(dist, params.length1) == "GT" {
                condition1 = true;
            }
            if realcompare(dist, params.length2) == "LT" {
                condition2 = true;
            }
        }

        cmv[12] = condition1 && condition2;
    }

    // LIC 14: Two conditions both must be true
    if numpoints >= 5 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..(numpoints - params.a_pts - params.b_pts - 2) {
            let j = i + params.a_pts + 1;
            let k = j + params.b_pts + 1;
            if !points_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius1) {
                condition1 = true;
            }
            if points_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], params.radius2) {
                condition2 = true;
            }
        }

        cmv[13] = condition1 && condition2;
    }

    // LIC 15: Two conditions both must be true
    if numpoints >= 5 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..(numpoints - params.e_pts - params.f_pts - 2) {
            let j = i + params.e_pts + 1;
            let k = j + params.f_pts + 1;
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, params.area1) == "GT" {
                condition1 = true;
            }
            if realcompare(area, params.area2) == "LT" {
                condition2 = true;
            }
        }

        cmv[14] = condition1 && condition2;
    }

    // Compute PUM (Preliminary Unlocking Matrix)
    let mut pum = vec![vec![false; 15]; 15];

    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                match input.lcm[i][j].as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = false,
                }
            }
        }
    }

    // Compute FUV (Final Unlocking Vector)
    let mut fuv = vec![false; 15];

    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&val| val);
        }
    }

    // Final launch decision
    let launch = fuv.iter().all(|&val| val);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
